AFTER UPDATE ON "ledger_camera_metrics_ring1"
FOR EACH ROW
WHEN NEW.updated_at = OLD.updated_at
BEGIN
  UPDATE "ledger_camera_metrics_ring1" SET updated_at = strftime('%Y-%m-%dT%H:%M:%fZ','now') WHERE id = NEW.id;
END;

CREATE VIEW IF NOT EXISTS "v_ledger_camera_metrics_ring1" AS
SELECT id, created_at, updated_at, producer, subject, severity, sequence_no
FROM "ledger_camera_metrics_ring1"
WHERE retained_until IS NULL OR retained_until >= strftime('%Y-%m-%dT%H:%M:%fZ','now');

CREATE TABLE IF NOT EXISTS "ledger_camera_metrics_ring2" (
  id INTEGER PRIMARY KEY,
  created_at TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%fZ','now')),
  updated_at TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%fZ','now')),
  producer TEXT NOT NULL,
  subject TEXT NOT NULL,
  severity TEXT NOT NULL DEFAULT 'info' CHECK (severity IN ('debug','info','notice','warning','error','critical')),
  sequence_no INTEGER NOT NULL DEFAULT 0 CHECK (sequence_no >= 0),
  payload_json TEXT NOT NULL DEFAULT '{}',
  previous_hash TEXT NOT NULL DEFAULT '',
  record_hash TEXT NOT NULL CHECK (length(record_hash) BETWEEN 1 AND 128),
  retained_until TEXT,
  signature TEXT NOT NULL DEFAULT ''
);

